// src/api/chatApi.js - HTTP + Socket.IO
import axios from "axios";
import { io } from "socket.io-client";

const API_BASE_URL = "https://capavate.com/";
const API_URL = `${API_BASE_URL}api/user/chatmessage`;

// ==================== SOCKET SETUP ====================
let socket = null;

export const initSocket = () => {
  if (socket && socket.connected) return socket;

  socket = io(API_BASE_URL, {
    transports: ["websocket", "polling"],
    reconnection: true,
    reconnectionAttempts: 5,
    reconnectionDelay: 1000,
  });

  socket.on("connect", () => {
    console.log("🟢 Socket connected:", socket.id);
  });

  socket.on("disconnect", () => {
    console.log("🔴 Socket disconnected");
  });

  socket.on("connect_error", (err) => {
    console.error("Socket connection error:", err.message);
  });

  return socket;
};

export const getSocket = () => socket;

export const disconnectSocket = () => {
  if (socket) {
    socket.disconnect();
    socket = null;
  }
};

// ==================== SOCKET EMITTERS ====================

export const joinConversation = (conversation_id) => {
  if (socket) socket.emit("join-conversation", conversation_id);
};

export const leaveConversation = (conversation_id) => {
  if (socket) socket.emit("leave-conversation", conversation_id);
};

export const emitTypingStart = (conversation_id, user_id, user_name) => {
  if (socket)
    socket.emit("typing-start", {
      conversation_id,
      user_id,
      user_name,
      isTyping: true,
    });
};

export const emitTypingEnd = (conversation_id, user_id) => {
  if (socket)
    socket.emit("typing-end", { conversation_id, user_id, isTyping: false });
};

export const emitMarkAsRead = (conversation_id, user_id) => {
  if (socket) socket.emit("mark-as-read", { conversation_id, user_id });
};

export const emitUserOnline = (user_id, user_type, user_name) => {
  if (socket) socket.emit("user-online", { user_id, user_type, user_name });
};

// ==================== SOCKET LISTENERS ====================

export const onNewMessage = (callback) => {
  if (socket) socket.on("new-message", callback);
};

export const onUserTyping = (callback) => {
  if (socket) socket.on("user-typing", callback);
};

export const onMessagesRead = (callback) => {
  if (socket) socket.on("messages-read", callback);
};

export const onUserStatusChange = (callback) => {
  if (socket) socket.on("user-status-change", callback);
};

export const onMessageNotification = (callback) => {
  if (socket) socket.on("message-notification", callback);
};

export const removeAllListeners = (events = []) => {
  if (!socket) return;
  if (events.length === 0) {
    socket.removeAllListeners();
  } else {
    events.forEach((e) => socket.off(e));
  }
};

// ==================== HTTP API CALLS ====================

export const getOrCreateConversation = async (
  participant1_type,
  participant1_id,
  participant2_type,
  participant2_id,
) => {
  try {
    const response = await axios.post(`${API_URL}/get_or_create_conversation`, {
      participant1_type,
      participant1_id,
      participant2_type,
      participant2_id,
    });
    return response.data;
  } catch (error) {
    console.error("getOrCreateConversation error:", error);
    throw error;
  }
};

export const getUserConversations = async (user_type, user_id) => {
  try {
    const response = await axios.post(`${API_URL}/get-user-conversations`, {
      user_type,
      user_id,
    });
    return response.data;
  } catch (error) {
    console.error("getUserConversations error:", error);
    throw error;
  }
};

export const getMessages = async (
  conversation_id,
  user_id,
  user_type,
  limit = 50,
  offset = 0,
) => {
  try {
    const response = await axios.post(`${API_URL}/get-messages`, {
      conversation_id,
      user_id,
      user_type,
      limit,
      offset,
    });
    return response.data;
  } catch (error) {
    console.error("getMessages error:", error);
    throw error;
  }
};

export const sendMessage = async (
  conversation_id,
  sender_type,
  sender_id,
  receiver_type,
  receiver_id,
  message,
) => {
  try {
    const response = await axios.post(
      `${API_URL}/send-message`,
      {
        conversation_id,
        sender_type,
        sender_id,
        receiver_type,
        receiver_id,
        message,
      },
      { headers: { "Content-Type": "application/json" } },
    );
    return response.data;
  } catch (error) {
    console.error("sendMessage error:", error);
    throw error;
  }
};

export const deleteMessage = async (message_id, user_id, user_type) => {
  try {
    const response = await axios.post(`${API_URL}/delete-message`, {
      message_id,
      user_id,
      user_type,
    });
    return response.data;
  } catch (error) {
    console.error("deleteMessage error:", error);
    throw error;
  }
};

export const uploadFile = async (formData) => {
  try {
    const response = await axios.post(`${API_URL}/upload-file`, formData, {
      headers: { "Content-Type": "multipart/form-data" },
    });
    return response.data;
  } catch (error) {
    console.error("uploadFile error:", error);
    throw error;
  }
};
